          title: { type: 'string', description: 'Brief title of the issue (one line)' },
          description: { type: 'string', description: 'Detailed description and a concrete fix suggestion' },
          file_path: { type: 'string', description: 'Repo-relative file path' },
          line_range: { type: 'string', description: 'Line range like "L123-L130", or "" if N/A' },
          severity: { type: 'string', enum: ['HIGH', 'MEDIUM', 'LOW'] },
          reason_category: { type: 'string', description: 'e.g. CLAUDE.md adherence, bug, historical git context, past PR comments, code comments compliance' },
          evidence: { type: 'string', description: 'Direct evidence quote/snippet supporting the finding' },
        },
        required: ['title', 'description', 'file_path', 'severity', 'reason_category', 'evidence'],
      },
    },
  },
  required: ['findings'],
}

const SCORE_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  properties: {
    score: { type: 'integer', minimum: 0, maximum: 100 },
    reason: { type: 'string', description: 'Brief justification: what you verified, why this score' },
  },
  required: ['score', 'reason'],
}

