const results = await pipeline(
  PRS,
  // ------------------------------------------------------------------
  // STAGE 1 — Setup (Haiku): get diff scope + CLAUDE.md inventory
  // ------------------------------------------------------------------
  async (pr) => {
    return await agent(
      `You are doing pre-review setup for PR #${pr.num} (${pr.note}) in ${REPO}.

The PR's head branch is fetched locally as ref \`${pr.branch}\` and the base is \`main\`.

Run these commands (cd into ${REPO} first):
  git diff main..${pr.branch} --stat
  gh pr view ${pr.num} --json body,title --jq .title
  gh pr view ${pr.num} --json body --jq '.body[0:1500]'
  find ${REPO} -name CLAUDE.md -not -path '*/node_modules/*' -not -path '*/.venv/*' -not -path '*/.git/*'

Then return:
- summary: 2-3 sentence summary of what the PR does
- files_changed: list of repo-relative file paths changed
- claudemd_files: list of repo-relative CLAUDE.md paths that may apply:
  - Always include the root CLAUDE.md if present
  - Include .claude/CLAUDE.md if present
  - For every directory containing a modified file, walk up and include any CLAUDE.md found along the way
  - Skip CLAUDE.md files that live under unrelated directories

Do NOT read the diff itself. Setup only.`,
      { schema: SETUP_SCHEMA, phase: 'Setup', label: `setup:${pr.num}` },
    )
  },
  // ------------------------------------------------------------------
  // STAGE 2 — Review (Sonnet x5 in parallel): the actual review
  // ------------------------------------------------------------------
  async (setup, pr) => {
    const ctx = `=== Context ===
PR #${pr.num} (${pr.note})
Branch: ${pr.branch}  (fetched locally; base: main)
Repo: ${REPO}

Files changed in this PR:
${(setup.files_changed || []).map((f) => `  - ${f}`).join('\n')}

Applicable CLAUDE.md files:
${(setup.claudemd_files || []).map((f) => `  - ${f}`).join('\n')}

Summary of what the PR does:
${setup.summary}

=== How to read the PR ===
  cd ${REPO}
  git diff main..${pr.branch}                  # full diff
  git diff main..${pr.branch} -- <path>        # per-file diff
  git show ${pr.branch}:<path>                 # full file at PR head

=== Project context ===
- Lock Code Manager is a Home Assistant integration that manages PIN codes on smart locks across providers (zwave_js, matter, zha, zigbee2mqtt, schlage, akuvox, virtual).
- The PRs migrate providers from a legacy slot-based API to a unified User→Credential model defined in custom_components/lock_code_manager/providers/_base.py (BaseLock).
- Exception contract in custom_components/lock_code_manager/domain/exceptions.py:
    - LockDisconnected: transport/unreachable, coordinator retries
    - LockOperationFailed: reachable but rejected (no retry)
    - CodeRejectedError: lock won't accept PIN
    - DuplicateCodeError: duplicate
    - ServiceValidationError is a HomeAssistantError subclass — order \`except\` clauses accordingly.
- Style note: \`except A, B:\` (no parens) is valid Python 3 (parser builds a tuple); it is used consistently across this codebase and pre-commit passes it. Do NOT report it as a SyntaxError.

=== Output ===
Return a JSON object with a \`findings\` array. Each finding must include title, description, file_path, line_range, severity (HIGH/MEDIUM/LOW), reason_category, and evidence.

False positives to skip:
- Pre-existing issues on main
- Things a linter/typechecker/CI would catch (formatting, missing imports, type errors)
- Pedantic nitpicks a senior engineer wouldn't call out
- Issues silenced explicitly in code (lint ignores, intentional comments)
- Changes that are clearly intentional and tied to the PR scope
- Real issues on lines NOT modified by this PR
- General "lack of tests" complaints unless the PR adds untested production logic
`

    return await parallel([
      // Review Agent #1: CLAUDE.md compliance
      () => agent(
        `${ctx}

You are Review Agent #1: CLAUDE.md compliance.

Step 1: Read each CLAUDE.md file listed above with the Read tool.
Step 2: Read the PR diff with \`git diff main..${pr.branch}\`.
Step 3: For each CLAUDE.md instruction, check whether the diff violates it. Note CLAUDE.md is guidance for Claude as it writes code, so not every instruction is applicable during review (skip "use TaskCreate", "prefer X tool" type directives).

Focus on adherence directives that the diff could violate:
- Style/structure rules (e.g. no inline imports, no nonlocal, no docstring Args/Returns sections, prefer comprehensions, spell out acronyms in comments)
- Test setup rules (proper setup/teardown, no manual hass.data manipulation)
- caplog rules (minimize text assertions)
- Tests-with-changes rules

Quote the relevant CLAUDE.md instruction in your evidence field.`,
        { schema: FINDINGS_SCHEMA, phase: 'Review', label: `review-claudemd:${pr.num}` },
      ),
      // Review Agent #2: Shallow bug scan
      () => agent(
        `${ctx}

You are Review Agent #2: Shallow bug scan.

Read ONLY the PR diff (\`git diff main..${pr.branch}\`). Avoid reading more context than the changes themselves.

Focus on LARGE bugs:
- Incorrect exception mapping (e.g. ServiceValidationError caught only under HomeAssistantError → wrong retry behavior)
- Off-by-one, null/None handling, missing guards on optional fields
- Race conditions, ordering bugs, lifecycle bugs (setup/teardown, push subscription lifecycle)
- Logic errors that flip a condition's intent
- Missing await on coroutines
- Iterating mutated data
- Silent swallowing of errors that the contract says should propagate
- Resources held past their scope (locks, subscriptions, file handles)
- API misuse (wrong helper signature, wrong arg position)

Ignore small issues, nitpicks, and likely false positives. Each finding's evidence must be a direct quote from the diff.`,
        { schema: FINDINGS_SCHEMA, phase: 'Review', label: `review-bugs:${pr.num}` },
      ),
      // Review Agent #3: Git history context
      () => agent(
        `${ctx}

You are Review Agent #3: Git blame / history context.

For each modified file in the PR:
- Run \`git log --oneline -20 -- <file>\` to see recent commits to that file.
- Run \`git log -p -10 -- <file>\` to see recent change content.
- For surprising deletions/replacements in the diff, use \`git blame -L <start>,<end> main -- <file>\` to find who/why originally added that code.

Identify bugs in light of history:
- A fix from a prior commit is being silently reverted by this PR.
- Code with a "DO NOT REMOVE" or "fixes <issue>" comment is being changed without justification.
- A subtle invariant that prior commits introduced is being broken.
- Code that was added to handle a specific bug class is being weakened.

Quote both the new change and the historical context in evidence.`,
        { schema: FINDINGS_SCHEMA, phase: 'Review', label: `review-history:${pr.num}` },
      ),
      // Review Agent #4: Past PR comments
      () => agent(
        `${ctx}

You are Review Agent #4: Past PR comments.

Find previous PRs that touched the same files and check for review comments that may apply here.

Useful commands:
  cd ${REPO}
  git log --oneline -20 -- <file>                  # find recent commits
  gh search prs --repo raman325/lock_code_manager --state merged <keyword>   # find prior PRs
  gh pr view <num> --json title,body
  gh api repos/raman325/lock_code_manager/pulls/<num>/comments --jq '.[] | {path, line, body}'

Also check this PR's existing review comments (Copilot, etc) to see if any open ones still apply:
  gh api repos/raman325/lock_code_manager/pulls/${pr.num}/comments --jq '.[] | {user: .user.login, path, line, body}'

For each finding, the evidence field must include the prior PR number and a quote of the original comment.`,
        { schema: FINDINGS_SCHEMA, phase: 'Review', label: `review-past-prs:${pr.num}` },
      ),
      // Review Agent #5: Code comments compliance
      () => agent(
        `${ctx}

You are Review Agent #5: Code comments compliance.

Read code comments (docstrings, inline comments, module headers) in the FILES MODIFIED by this PR.

Check whether the actual code changes comply with what the comments say:
- A docstring promises "always wraps in X" but the code path does not.
- An inline comment says "do not call this with Y=None" but the new caller passes None.
- A module header documents an invariant (e.g. "credentials are write-only on this provider") that the change breaks.
- A "# TODO: handle Z" left by a prior author that this PR's change now needs to address.
- An ARCHITECTURE.md / inline doc referenced in a comment whose stated contract is violated.

Quote the relevant comment in evidence and the conflicting change.`,
        { schema: FINDINGS_SCHEMA, phase: 'Review', label: `review-comments:${pr.num}` },
      ),
    ])
  },
  // ------------------------------------------------------------------
  // STAGE 3 — Score (Haiku per finding): confidence 0-100
  // ------------------------------------------------------------------
  async (reviews, pr) => {
    const allFindings = (reviews || [])
      .filter(Boolean)
      .flatMap((r) => (r && r.findings) || [])
    log(`PR #${pr.num}: ${allFindings.length} raw findings to score`)
    if (allFindings.length === 0) {
      return { pr, findings: [] }
    }
    const ctx = `PR #${pr.num} (${pr.note}) — branch ${pr.branch} — repo ${REPO}
To verify, use:
  cd ${REPO}
  git diff main..${pr.branch} -- <file>
  git show ${pr.branch}:<file>
  Read <file> at the line range mentioned in the finding.

Rubric (use the integer score):
- 0: Not confident at all. False positive that doesn't stand up to light scrutiny, or pre-existing issue on main.
- 25: Somewhat confident. Might be a real issue, but might also be false positive. Couldn't verify.
- 50: Moderately confident. Verified it's real, but might be a nitpick or rare in practice. Not very important.
- 75: Highly confident. Double-checked. Likely real and will impact functionality, OR directly violates a CLAUDE.md instruction.
- 100: Absolutely certain. Confirmed real, will hit frequently. Evidence directly confirms.

For CLAUDE.md findings, double-check that the cited CLAUDE.md actually states the specific instruction. If it doesn't, score below 50.

Note: \`except A, B:\` (no parens) is valid Python 3 in this codebase — score any "SyntaxError" claim about this pattern at 0.`
    const scored = await parallel(
      allFindings.map((f, i) => async () => {
        const result = await agent(
          `${ctx}

Finding to score:
${JSON.stringify(f, null, 2)}

Verify by reading the cited file at the cited line range. Then score 0-100 and give a brief reason.`,
          { schema: SCORE_SCHEMA, phase: 'Score', label: `score:${pr.num}:${i}` },
        )
        return { ...f, score: result.score, score_reason: result.reason }
      }),
    )
    return { pr, findings: scored.filter(Boolean) }
  },
  // ------------------------------------------------------------------
  // STAGE 4 — Filter / synthesize (plain code, no agent)
  // ------------------------------------------------------------------
  (result, pr) => {
    const findings = (result && result.findings) || []
    return {
      pr_num: pr.num,
      pr_note: pr.note,
      merged: !!pr.merged,
      total_raw_findings: findings.length,
      high_confidence: findings.filter((f) => f.score >= 80),
      medium_confidence: findings.filter((f) => f.score >= 50 && f.score < 80),
      low_confidence: findings.filter((f) => f.score < 50),
    }
  },
)

log(`All PRs reviewed. Summary:`)
for (const r of results.filter(Boolean)) {
  log(
    `  PR #${r.pr_num} ${r.merged ? '(merged)' : ''}: ${r.high_confidence.length} high, ${r.medium_confidence.length} medium, ${r.low_confidence.length} low (of ${r.total_raw_findings} raw)`,
  )
}

return results.filter(Boolean)

